import React from "react";
import CIcon from "@coreui/icons-react";
import {
  cilAccountLogout,
  cilBell,
  cilCalculator,
  cilChartPie,
  cilCursor,
  cilDescription,
  cilDrop,
  cilNotes,
  cilPencil,
  cilPuzzle,
  cilSpeedometer,
  cilStar,
} from "@coreui/icons";
import { CNavGroup, CNavItem, CNavTitle } from "@coreui/react";

const _nav = [
  {
    component: CNavGroup,
    name: 'Career',
    to: '/base',
    icon: <CIcon icon={cilPuzzle} customClassName="nav-icon" />,
    items: [
      {
        component: CNavItem,
        name: 'Departments',
        to: '/career/department',
      },
      {
        component: CNavItem,
        name: 'Positions',
        to: '/career/position',
      },
      {
        component: CNavItem,
        name: 'Applicants',
        to: '/career/applicant',
      },
    ],
  },


];

export default _nav;
